bad_example:
for record in batch:
    try:
        session.execute(insert(Model).values(**record))
        session.commit()  # commits after every row — partial writes on failure
    except Exception as e:
        log.warning('row failed: %s', e)
        # continue with next record — DB now has subset of batch

good_example:
try:
    with session.begin():  # single transaction for entire batch
        for record in batch:
            session.execute(insert(Model).values(**record))
    # committed atomically — either all succeed or none do
except Exception:
    log.error('batch failed, rolled back %d records', len(batch))
    raise
